# manifests/site.pp — Nginx configuration

class nginx {
  package { "nginx":
    ensure  => installed,
  }

  service { "nginx":
    ensure    => running,
    enable    => true,
    subscribe => File["/etc/nginx/nginx.conf"],
  }

  file { "/etc/nginx/nginx.conf":
    ensure  => file,
    owner   => "root",
    group   => "root",
    mode    => "0644",
    content => template("nginx/nginx.conf.erb"),
  }

  file { "/var/www/html/index.html":
    ensure  => file,
    content => "<h1>Managed by Puppet</h1>",
    mode    => "0644",
  }
}

# Node classification
node "web-01.example.com" {
  include nginx
  include monitoring
}

# Profile: wraps nginx module with org config
# profiles/manifests/nginx.pp
class profiles::nginx {
  class { "nginx":
    worker_processes => 4,
    server_name      => "example.com",
  }

  file { "/etc/nginx/conf.d/security.conf":
    ensure => file,
    source => "puppet:///modules/profiles/security.conf",
    notify => Service["nginx"],
  }
}

# Role: composes profiles for a web server
# roles/manifests/webserver.pp
class roles::webserver {
  include profiles::nginx
  include profiles::php
  include profiles::monitoring
}

# Node classification
node "web-01" {
  include roles::webserver
}

